/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * <Replace with your name(s) and NetID(s).>
 */

#include <assert.h>

#include "csapp.h"

/* Number of pre-created worker threads. */
#define NTHREADS  8

/* Capacity of the shared connection buffer. */
#define SBUFSIZE  16

/*
 * Holds an accepted connection's file descriptor and client socket address.
 * The main thread allocates one of these per accepted connection and puts it
 * into the shared buffer; worker threads free it after handling the request.
 */
typedef struct {
	int			connfd;
	struct sockaddr_in	clientaddr;
} conn_info_t;

/*
 * A bounded, thread-safe FIFO buffer for conn_info_t pointers.
 * Synchronization uses a mutex and two condition variables (not semaphores),
 * as required by the assignment.
 */
typedef struct {
	conn_info_t	**buf;		/* Circular buffer of pointers       */
	int		  n;		/* Capacity of the buffer            */
	int		  front;	/* Monotone index of oldest item     */
	int		  rear;		/* Monotone index past newest item   */
	pthread_mutex_t	  mutex;	/* Mutual exclusion for all fields   */
	pthread_cond_t	  not_full;	/* Signaled when a slot becomes free */
	pthread_cond_t	  not_empty;	/* Signaled when an item is added    */
} sbuf_t;

/* Log file opened once at startup; all writes are mutex-protected. */
static FILE		*log_file;
static pthread_mutex_t	 log_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Shared connection buffer (producer: main; consumers: worker threads). */
static sbuf_t		 sbuf;

static void		 client_error(int fd, const char *cause, int err_num,
			     const char *short_msg, const char *long_msg);
static char		*create_log_entry(const struct sockaddr_in *sockaddr,
			     const char *uri, int size);
static int		 parse_uri(const char *uri, char **hostnamep,
			     char **portp, char **pathnamep);
static void		 sbuf_init(sbuf_t *sp, int n);
static void		 sbuf_deinit(sbuf_t *sp);
static void		 sbuf_insert(sbuf_t *sp, conn_info_t *item);
static conn_info_t	*sbuf_remove(sbuf_t *sp);
static void		*thread(void *vargp);
static void		 handle_request(int connfd,
			     struct sockaddr_in *clientaddr);

/*
 * Requires:
 *   argc == 2 and argv[1] is a valid port number string in [18000, 18200].
 *
 * Effects:
 *   Opens the log file once, initializes the shared buffer, spawns NTHREADS
 *   worker threads, opens a listening socket on the given port, and loops
 *   forever accepting connections and enqueuing them for workers to handle.
 */
int
main(int argc, char **argv)
{
	int listenfd;
	socklen_t clientlen;
	conn_info_t *ci;
	pthread_t tid;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/*
	 * Ignore SIGPIPE.  Writing to a connection closed by the peer would
	 * otherwise deliver SIGPIPE whose default action terminates the process.
	 */
	Signal(SIGPIPE, SIG_IGN);

	/* Open the log file once during initialization. */
	if ((log_file = fopen("proxy.log", "a")) == NULL) {
		fprintf(stderr, "Error: cannot open proxy.log\n");
		exit(1);
	}

	/* Initialize the shared connection buffer. */
	sbuf_init(&sbuf, SBUFSIZE);

	/* Pre-spawn the pool of worker threads. */
	for (int i = 0; i < NTHREADS; i++)
		Pthread_create(&tid, NULL, thread, NULL);

	/* Open the listening socket. */
	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Error: cannot listen on port %s\n", argv[1]);
		exit(1);
	}

	/* Accept connections and hand them off to worker threads. */
	while (1) {
		clientlen = sizeof(struct sockaddr_in);
		ci = Malloc(sizeof(conn_info_t));
		ci->connfd = Accept(listenfd, (SA *)&ci->clientaddr,
		    &clientlen);
		sbuf_insert(&sbuf, ci);
	}

	/* Not reached. */
	sbuf_deinit(&sbuf);
	fclose(log_file);
	return (0);
}

/*
 * Requires:
 *   The global sbuf must be initialized.
 *
 * Effects:
 *   Runs as a detached peer thread.  Loops forever: removes a conn_info_t
 *   from the buffer, handles the HTTP request, closes the socket, and frees
 *   the conn_info_t.
 */
static void *
thread(void *vargp)
{
	(void)vargp;
	Pthread_detach(Pthread_self());
	while (1) {
		conn_info_t *ci = sbuf_remove(&sbuf);
		handle_request(ci->connfd, &ci->clientaddr);
		close(ci->connfd);
		free(ci);
	}
	return (NULL);
}

/*
 * Requires:
 *   connfd is an open socket connected to the client.
 *   clientaddr points to the client's socket address structure.
 *
 * Effects:
 *   Reads a single HTTP GET request from the client, connects to the end
 *   server, rewrites the request (HTTP/1.0, path-only URI, no connection
 *   management headers, adds Connection: close), forwards the server's
 *   response back to the client, and appends a log entry.  All open
 *   descriptors and allocated memory are released before returning, whether
 *   the transaction succeeds or fails.
 */
static void
handle_request(int connfd, struct sockaddr_in *clientaddr)
{
	rio_t	 client_rio, server_rio;
	char	 buf[MAXLINE], method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char	 header_line[MAXLINE];
	char	*hostname = NULL, *port = NULL, *pathname = NULL;
	char	 resp_buf[MAXBUF];
	int	 serverfd = -1;
	int	 total_bytes = 0;
	ssize_t	 n;

	/* Set up buffered I/O for the client socket. */
	rio_readinitb(&client_rio, connfd);

	/* Read the HTTP request line. */
	if ((n = rio_readlineb(&client_rio, buf, MAXLINE)) <= 0) {
		client_error(connfd, "Empty request", 400, "Bad Request",
		    "Cannot read HTTP request line");
		goto cleanup;
	}

	/* Parse the request line: METHOD URI HTTP-VERSION. */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(connfd, buf, 400, "Bad Request",
		    "Malformed HTTP request line");
		goto cleanup;
	}
	(void)version;		/* Version is read but not used further. */

	/* Only the GET method is supported. */
	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented",
		    "This proxy supports only the GET method");
		goto cleanup;
	}

	/* Extract hostname, port, and path from the URI. */
	if (parse_uri(uri, &hostname, &port, &pathname) != 0) {
		client_error(connfd, uri, 400, "Bad Request",
		    "Cannot parse the request URI");
		goto cleanup;
	}

	/* Connect to the end server. */
	if ((serverfd = open_clientfd(hostname, port)) < 0) {
		client_error(connfd, hostname, 404, "Not Found",
		    "Cannot connect to the end server");
		goto cleanup;
	}

	/*
	 * Send the rewritten request line to the server.  We always use
	 * HTTP/1.0 (which implies non-persistent connections) and replace the
	 * full URI with just the path component.
	 */
	snprintf(buf, MAXLINE, "GET %s HTTP/1.0\r\n", pathname);
	if (rio_writen(serverfd, buf, strlen(buf)) < 0)
		goto cleanup;

	/*
	 * Forward the client's request headers to the server, skipping any
	 * connection-management headers so the server will not attempt to
	 * keep the connection alive.
	 */
	while ((n = rio_readlineb(&client_rio, header_line, MAXLINE)) > 0) {
		if (strcmp(header_line, "\r\n") == 0)
			break;			/* End of headers. */
		if (strncasecmp(header_line, "Connection:", 11) == 0 ||
		    strncasecmp(header_line, "Keep-Alive:", 11) == 0 ||
		    strncasecmp(header_line, "Proxy-Connection:", 17) == 0)
			continue;		/* Strip this header. */
		if (rio_writen(serverfd, header_line,
		    strlen(header_line)) < 0)
			goto cleanup;
	}

	/* Append Connection: close and the blank line that ends the headers. */
	if (rio_writen(serverfd, "Connection: close\r\n\r\n",
	    strlen("Connection: close\r\n\r\n")) < 0)
		goto cleanup;

	/* Set up buffered I/O for the server socket. */
	rio_readinitb(&server_rio, serverfd);

	/*
	 * Read the server's response and forward it to the client in MAXBUF
	 * chunks.  Count the total bytes received for the log entry.
	 */
	while ((n = rio_readnb(&server_rio, resp_buf, MAXBUF)) > 0) {
		if (rio_writen(connfd, resp_buf, n) < 0)
			break;
		total_bytes += n;
	}

	/* Log the transaction if the server sent any data. */
	if (total_bytes > 0) {
		char *log_entry = create_log_entry(clientaddr, uri,
		    total_bytes);
		pthread_mutex_lock(&log_mutex);
		fprintf(log_file, "%s\n", log_entry);
		fflush(log_file);
		pthread_mutex_unlock(&log_mutex);
		free(log_entry);
	}

cleanup:
	if (serverfd >= 0)
		close(serverfd);
	free(hostname);
	free(port);
	free(pathname);
}

/*
 * Requires:
 *   n > 0.
 *
 * Effects:
 *   Initializes a bounded shared buffer sp with capacity n.
 */
static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Calloc(n, sizeof(conn_info_t *));
	sp->n = n;
	sp->front = 0;
	sp->rear = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->not_full, NULL);
	pthread_cond_init(&sp->not_empty, NULL);
}

/*
 * Requires:
 *   sp was initialized with sbuf_init.
 *
 * Effects:
 *   Frees all resources associated with sp.
 */
static void
sbuf_deinit(sbuf_t *sp)
{
	free(sp->buf);
	pthread_mutex_destroy(&sp->mutex);
	pthread_cond_destroy(&sp->not_full);
	pthread_cond_destroy(&sp->not_empty);
}

/*
 * Requires:
 *   sp was initialized with sbuf_init.
 *   item is a non-NULL conn_info_t pointer.
 *
 * Effects:
 *   Inserts item at the rear of the buffer, blocking if the buffer is full.
 */
static void
sbuf_insert(sbuf_t *sp, conn_info_t *item)
{
	pthread_mutex_lock(&sp->mutex);
	while ((sp->rear - sp->front) >= sp->n)
		pthread_cond_wait(&sp->not_full, &sp->mutex);
	sp->buf[sp->rear % sp->n] = item;
	sp->rear++;
	pthread_cond_signal(&sp->not_empty);
	pthread_mutex_unlock(&sp->mutex);
}

/*
 * Requires:
 *   sp was initialized with sbuf_init.
 *
 * Effects:
 *   Removes and returns the conn_info_t at the front of the buffer, blocking
 *   if the buffer is empty.
 */
static conn_info_t *
sbuf_remove(sbuf_t *sp)
{
	conn_info_t *item;

	pthread_mutex_lock(&sp->mutex);
	while (sp->front >= sp->rear)
		pthread_cond_wait(&sp->not_empty, &sp->mutex);
	item = sp->buf[sp->front % sp->n];
	sp->front++;
	pthread_cond_signal(&sp->not_full);
	pthread_mutex_unlock(&sp->mutex);
	return (item);
}

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}
